function pfraAgeBand(age){
  age=parseInt(age||0);
  if(age<25)return "u25";
  if(age<30)return "25-29";
  if(age<35)return "30-34";
  if(age<40)return "35-39";
  if(age<45)return "40-44";
  if(age<50)return "45-49";
  if(age<55)return "50-54";
  if(age<60)return "55-59";
  return "60+";
}
function pfraParseNumber(value){
  if(value===null||value===undefined)return null;
  let s=String(value).replace(/[≥≤*]/g,"").trim();
  let n=parseFloat(s);
  return isNaN(n)?null:n;
}
function pfraTimeSeconds(value){
  if(value===null||value===undefined||value==="")return null;
  let s=String(value).replace(/[≥≤*]/g,"").trim();
  if(s.includes(":")){
    let parts=s.split(":").map(Number);
    if(parts.some(isNaN))return null;
    return parts[0]*60+parts[1];
  }
  let n=parseFloat(s);
  return isNaN(n)?null:n;
}
function pfraScoreReps(event,ageBand,sex,reps){
  if(reps===null||isNaN(reps))return 0;
  for(const row of pfraTables[event]){
    let threshold=pfraParseNumber(row[ageBand][sex]);
    if(threshold!==null && reps>=threshold)return row.points;
  }
  return 0;
}
function pfraScoreTime(event,ageBand,sex,seconds,lowerIsBetter){
  if(seconds===null||isNaN(seconds))return 0;
  for(const row of pfraTables[event]){
    let threshold=pfraTimeSeconds(row[ageBand][sex]);
    if(threshold===null)continue;
    if(lowerIsBetter && seconds<=threshold)return row.points;
    if(!lowerIsBetter && seconds>=threshold)return row.points;
  }
  return 0;
}
function pfraScoreWHtR(ratio){
  if(!isFinite(ratio))return 0;
  if(ratio<=0.49)return 20;
  if(ratio<=0.50)return 19;
  if(ratio<=0.51)return 18;
  if(ratio<=0.52)return 17;
  if(ratio<=0.53)return 16;
  if(ratio<=0.54)return 15;
  if(ratio<=0.55)return 12.5;
  if(ratio<=0.56)return 10;
  if(ratio<=0.57)return 7.5;
  if(ratio<=0.58)return 5;
  if(ratio<=0.59)return 2.5;
  return 0;
}
function renderPFRAInputs(){
  let cardio=document.getElementById("pfraCardioEvent")?.value;
  document.getElementById("pfraRunWrap")?.classList.toggle("hidden",cardio!=="run2");
  document.getElementById("pfraHamrWrap")?.classList.toggle("hidden",cardio!=="hamr");
  let core=document.getElementById("pfraCoreEvent")?.value;
  document.getElementById("pfraCoreRepsWrap")?.classList.toggle("hidden",core==="plank");
  document.getElementById("pfraPlankWrap")?.classList.toggle("hidden",core!=="plank");
}
function getPFRAResult(){
  let age=parseInt(document.getElementById("pfraAge")?.value||0);
  let band=pfraAgeBand(age);
  let sex=document.getElementById("pfraSex")?.value||"M";
  let height=parseFloat(document.getElementById("pfraHeight")?.value||0);
  let waist=parseFloat(document.getElementById("pfraWaist")?.value||0);
  let ratio=(height>0)?waist/height:NaN;
  let whtrPoints=pfraScoreWHtR(ratio);

  let cardioEvent=document.getElementById("pfraCardioEvent")?.value||"run2";
  let cardioPoints=0,cardioValue="";
  if(cardioEvent==="run2"){
    cardioValue=document.getElementById("pfraRunTime")?.value||"";
    cardioPoints=pfraScoreTime("run2",band,sex,pfraTimeSeconds(cardioValue),true);
  } else {
    cardioValue=document.getElementById("pfraHamr")?.value||"";
    cardioPoints=pfraScoreReps("hamr",band,sex,parseFloat(cardioValue));
  }

  let strengthEvent=document.getElementById("pfraStrengthEvent")?.value||"pushups";
  let strengthValue=parseFloat(document.getElementById("pfraStrengthReps")?.value||0);
  let strengthPoints=pfraScoreReps(strengthEvent,band,sex,strengthValue);

  let coreEvent=document.getElementById("pfraCoreEvent")?.value||"situps";
  let coreValue="",corePoints=0;
  if(coreEvent==="plank"){
    coreValue=document.getElementById("pfraPlankTime")?.value||"";
    corePoints=pfraScoreTime("plank",band,sex,pfraTimeSeconds(coreValue),false);
  } else {
    coreValue=document.getElementById("pfraCoreReps")?.value||"";
    corePoints=pfraScoreReps(coreEvent,band,sex,parseFloat(coreValue));
  }

  let total=cardioPoints+whtrPoints+strengthPoints+corePoints;
  let componentMinimums=cardioPoints>=30 && whtrPoints>=2.5 && strengthPoints>=2.5 && corePoints>=2.5;
  let pass=total>=75 && componentMinimums;
  let rating=pass?(total>=90?"Excellent":"Satisfactory"):"Unsatisfactory";
  return {date:document.getElementById("pfraDate")?.value||today(),age,band,sex,height,waist,ratio,whtrPoints,cardioEvent,cardioValue,cardioPoints,strengthEvent,strengthValue,strengthPoints,coreEvent,coreValue,corePoints,total,pass,rating,componentMinimums};
}
function calculatePFRA(){
  if(!document.getElementById("pfraResults"))return;
  let r=getPFRAResult();
  let ratioText=isFinite(r.ratio)?r.ratio.toFixed(2):"—";
  let statusClass=r.pass?"pfra-pass":"pfra-fail";
  let minText=r.componentMinimums?"Component minimums met":"One or more component minimums not met";
  document.getElementById("pfraResults").innerHTML=`
    <div class="pfra-score ${statusClass}">${r.total.toFixed(1)} / 100</div>
    <div class="${statusClass}"><strong>${r.rating}</strong></div>
    <div class="pfra-grid">
      <div class="pfra-result-card">Cardio<br><strong>${r.cardioPoints.toFixed(1)} / 50</strong></div>
      <div class="pfra-result-card">WHtR ${ratioText}<br><strong>${r.whtrPoints.toFixed(1)} / 20</strong></div>
      <div class="pfra-result-card">Strength<br><strong>${r.strengthPoints.toFixed(1)} / 15</strong></div>
      <div class="pfra-result-card">Core<br><strong>${r.corePoints.toFixed(1)} / 15</strong></div>
    </div>
    <p class="${r.componentMinimums?"pfra-pass":"pfra-warn"}">${minText}</p>`;
}
function savePFRA(){
  let d=data(); if(!d.pfraHistory)d.pfraHistory=[];
  d.pfraHistory.push({profileId:prof().id,...getPFRAResult()});
  save(d);renderPFRAHistory();alert("Practice PFRA saved.");
}
function renderPFRAHistory(){
  let el=document.getElementById("pfraHistory");if(!el)return;
  let hist=(data().pfraHistory||[]).filter(x=>x.profileId===prof().id).slice().reverse();
  el.innerHTML=hist.length?hist.map(x=>`<div class="history-row"><strong>${x.date}</strong> - ${Number(x.total).toFixed(1)} (${x.rating})<br>Cardio ${x.cardioPoints} | WHtR ${x.whtrPoints} | Strength ${x.strengthPoints} | Core ${x.corePoints}</div>`).join(""):"No saved practice assessments.";
}
let practiceInterval=null,practiceRemaining=0,practiceOriginal=0;
function practiceClockRender(){
  let m=String(Math.floor(practiceRemaining/60)).padStart(2,"0");
  let s=String(practiceRemaining%60).padStart(2,"0");
  let el=document.getElementById("practiceClock");if(el)el.innerText=`${m}:${s}`;
}
function startPracticeTimer(){
  if(practiceRemaining<=0){practiceOriginal=parseInt(document.getElementById("practiceTimerType").value);practiceRemaining=practiceOriginal;}
  clearInterval(practiceInterval);practiceClockRender();
  practiceInterval=setInterval(()=>{practiceRemaining--;practiceClockRender();if(practiceRemaining<=0){clearInterval(practiceInterval);alert("Timer complete.");}},1000);
}
function pausePracticeTimer(){clearInterval(practiceInterval)}
function resetPracticeTimer(){clearInterval(practiceInterval);practiceRemaining=parseInt(document.getElementById("practiceTimerType").value);practiceClockRender()}

function data(){return JSON.parse(localStorage.getItem("missionReadyV27")||JSON.stringify(defaultData))}function save(d){localStorage.setItem("missionReadyV27",JSON.stringify(d))}function today(){return new Date().toISOString().split("T")[0]}function prof(){let d=data();return d.profiles.find(p=>p.id===d.activeProfileId)||d.profiles[0]}function val(id){return document.getElementById(id).value}function num(id){let n=parseFloat(val(id));return isNaN(n)?0:n}function showTab(id){
 document.querySelectorAll(".tab").forEach(x=>x.classList.add("hidden"));
 const tab=document.getElementById(id);
 if(tab)tab.classList.remove("hidden");
 localStorage.setItem("missionReadyLastTab",id);
 if(id==="intel")renderProgress();
 if(id==="library")renderLibrary();
 if(id==="diagrams")renderDiagrams();
 if(id==="pfra"){renderPFRAInputs();calculatePFRA();renderPFRAHistory();}
}
function init(){let d=data();if(!d.targets)d.targets=defaultData.targets;save(d);document.getElementById("dailyDate").value=today();document.getElementById("workoutDate").value=today();if(document.getElementById("pfraDate"))document.getElementById("pfraDate").value=today();let w=document.getElementById("weekSelect");for(let i=1;i<=12;i++)w.innerHTML+=`<option value="${i}">Week ${i}</option>`;document.getElementById("workoutSelect").innerHTML=Object.keys(templates).map(x=>`<option>${x}</option>`).join("");let exs=[...new Set(Object.values(templates).flat().map(e=>e.name))].sort();document.getElementById("librarySelect").innerHTML=exs.map(x=>`<option>${x}</option>`).join("");renderProfiles();renderTargets();renderMission();loadWorkout();renderProgress();updateNetCarbsPreview();renderLibrary();renderDiagrams();renderPFRAInputs();calculatePFRA();renderPFRAHistory();let last=localStorage.getItem("missionReadyLastTab");if(last&&document.getElementById(last))showTab(last)}
function renderProfiles(){let d=data(),p=prof();document.getElementById("profileSelect").innerHTML=d.profiles.map(x=>`<option value="${x.id}">${x.name}</option>`).join("");document.getElementById("profileSelect").value=d.activeProfileId;document.getElementById("goalChip").innerText=`${p.name}: ${p.startWaist??"—"}” → ${p.goalWaist??"—"}” waist`;document.getElementById("profileList").innerHTML=d.profiles.map(x=>`<div class="stat"><b>${x.name}</b><br>Start: ${x.startWeight??"—"} lb / ${x.startWaist??"—"}” waist<br>Goal waist: ${x.goalWaist??"—"}”</div>`).join("")}
function changeProfile(){let d=data();d.activeProfileId=val("profileSelect");save(d);renderProfiles();renderMission();loadWorkout();renderProgress()}function renderTargets(){let t=data().targets;["Calories","Protein","Fiber","NetCarbs","Water","Sleep"].forEach(k=>document.getElementById("target"+k).value=t[k.charAt(0).toLowerCase()+k.slice(1)])}
function saveTargets(){let d=data();d.targets={calories:num("targetCalories"),protein:num("targetProtein"),fiber:num("targetFiber"),netCarbs:num("targetNetCarbs"),water:num("targetWater"),sleep:num("targetSleep")};save(d);renderMission();updateNetCarbsPreview();alert("Targets saved.")}
function missionKey(){return prof().id+"_"+today()}function renderMission(){let d=data(),p=prof(),m=d.missions[missionKey()]||{},items=["Workout complete","Protein target hit","Calories within target","Steps ≥ 10,000","Water target hit","Sleep target hit"],completed=items.filter((_,i)=>m[i]).length,pct=Math.round(completed/items.length*100);let dow=new Date().getDay();document.getElementById("weeklyReminder").innerHTML=(dow===0)?`<div class="reminder"><b>Sunday Check-In:</b> measure waist and weight today. Same tape location, relaxed at navel.</div>`:"";document.getElementById("missionProgress").innerHTML=`<b>Mission Progress: ${completed}/${items.length} (${pct}%)</b><div class="bar"><div class="barFill" style="width:${pct}%"></div></div>`;document.getElementById("missionList").innerHTML=items.map((x,i)=>`<label class="mission-item"><input type="checkbox" id="m${i}" ${m[i]?"checked":""}> ${x}</label>`).join("");let daily=d.daily.filter(x=>x.profileId===p.id),work=d.workouts.filter(x=>x.profileId===p.id),last=daily[daily.length-1]||{},waistLost=(p.startWaist&&last.waist)?(p.startWaist-parseFloat(last.waist)).toFixed(1):"—",wtLost=(p.startWeight&&last.weight)?(p.startWeight-parseFloat(last.weight)).toFixed(1):"—";document.getElementById("snapshot").innerHTML=`<div class="stat">Latest Weight<div class="big">${last.weight||"—"} lb</div>${wtLost} lb lost</div><div class="stat">Latest Waist<div class="big">${last.waist||"—"}”</div>${waistLost}” lost</div><div class="stat">Steps<div class="big">${last.steps||"—"}</div>from watch/manual</div><div class="stat">Workouts<div class="big">${work.length}</div>logged</div>`}
function saveMission(){let d=data();d.missions[missionKey()]={};for(let i=0;i<6;i++)d.missions[missionKey()][i]=document.getElementById("m"+i).checked;save(d);renderMission();alert("Mission saved.")}function copyShareLink(){navigator.clipboard?.writeText(location.href.split("#")[0]);alert("Copied: "+location.href.split("#")[0])}
function updateNetCarbsPreview(){let carbs=num("carbs"),fiber=num("fiber"),net=Math.max(0,carbs-fiber);document.getElementById("netCarbs").value=(carbs||fiber)?net:"";let score=nutritionScore({calories:val("calories"),protein:val("protein"),fiber:val("fiber"),netCarbs:net,water:val("water"),sleepHours:val("sleepHours"),sleepMinutes:val("sleepMinutes")});document.getElementById("nutritionScorePreview").innerHTML=`<b>Nutrition Score Preview:</b> ${score}/100 <span class="pill">Net carbs: ${net}g</span>`}
function sleepDecimal(o){return (parseFloat(o.sleepHours||0)+(parseFloat(o.sleepMinutes||0)/60))}function nutritionScore(e){let t=data().targets,score=0,c=parseFloat(e.calories),p=parseFloat(e.protein),f=parseFloat(e.fiber),n=parseFloat(e.netCarbs),w=parseFloat(e.water),s=e.sleep!==undefined?parseFloat(e.sleep):sleepDecimal(e);if(c>0)score+=c<=t.calories?25:c<=t.calories+200?18:c<=t.calories+400?10:0;if(!isNaN(p))score+=Math.min(25,Math.round(p/t.protein*25));if(!isNaN(f))score+=Math.min(15,Math.round(f/t.fiber*15));if(!isNaN(n))score+=n<=t.netCarbs?10:n<=t.netCarbs+50?5:0;if(!isNaN(w))score+=Math.min(10,Math.round(w/t.water*10));if(!isNaN(s))score+=Math.min(15,Math.round(s/t.sleep*15));return Math.max(0,Math.min(100,score))}
function adj(w){w=parseInt(w);return w<=4?{upper:0,lower:0}:w<=8?{upper:5,lower:10}:{upper:10,lower:20}}function lastExercise(pid,name){let all=data().workouts.filter(w=>w.profileId===pid).flatMap(w=>w.exercises||[]).filter(e=>e.name===name);return all[all.length-1]}
function targetSets(ex,week){let a=adj(week),d=data(),key=prof().id+"_"+ex.name,saved=d.trainingMaxes[key];return ex.sets.map(s=>{let [label,wt,reps]=s;if(saved&&label!=="Warm-up"&&ex.type!=="cardio"&&ex.type!=="core")wt=saved;else if(label!=="Warm-up"&&ex.type==="upper")wt+=a.upper;else if(label!=="Warm-up"&&ex.type==="lower")wt+=a.lower;return{label,weight:wt,reps}})}
function loadWorkout(){let day=val("workoutSelect"),week=val("weekSelect"),list=templates[day];document.getElementById("exerciseNav").innerHTML=list.map((e,i)=>`<button onclick="scrollToExercise(${i})">${i+1}. ${e.name}</button>`).join("");document.getElementById("historyExercise").innerHTML=[...new Set(Object.values(templates).flat().map(e=>e.name))].sort().map(x=>`<option>${x}</option>`).join("");document.getElementById("workoutContainer").innerHTML=list.map((ex,ei)=>{let last=lastExercise(prof().id,ex.name),prev=last?last.sets.map(s=>`${s.weight}x${s.reps}${s.done?" ✓":""}`).join(", "):"No previous data",sets=targetSets(ex,week);return`<div class="exercise-card" id="exercise${ei}" data-name="${ex.name}" data-type="${ex.type}"><div class="exercise-count">Exercise ${ei+1} of ${list.length}</div><div class="exercise-title"><h3>${ex.name}</h3><span>Rest: ${ex.rest||0}s</span></div><button id="helpbtn-${safeId(ex.name)}" class="help-btn" onclick="toggleHelp(\`${ex.name}\`)">▶ Exercise Help</button>${helpHtml(ex.name)}<div class="previous"><b>Previous:</b> ${prev}</div><div class="exercise-rpe"><label>Exercise RPE (1–10)<input type="number" id="e${ei}rpe" min="1" max="10" step="0.5" placeholder="8"></label><label>Exercise Note<input type="text" id="e${ei}note" placeholder="Shoulder, machine used, substitution..."></label></div><table class="set-table"><thead><tr><th>Set</th><th>Weight</th><th>Reps</th><th>Done</th></tr></thead><tbody>${sets.map((s,si)=>`<tr><td>${s.label}</td><td><input type="number" step="0.5" id="e${ei}s${si}w" value="${s.weight}"></td><td><input type="number" id="e${ei}s${si}r" value="${s.reps}"></td><td><input type="checkbox" id="e${ei}s${si}d" onchange="maybeStartRest(${ex.rest||0})"></td></tr>`).join("")}</tbody></table></div>`}).join("");renderHistory()}
function scrollToExercise(i){document.getElementById("exercise"+i).scrollIntoView({behavior:"smooth"})}function maybeStartRest(s){if(s>0)startTimer(s)}let timer=null,endTime=null;function startTimer(sec){clearInterval(timer);endTime=Date.now()+sec*1000;tick();timer=setInterval(tick,250)}function tick(){let left=Math.max(0,Math.round((endTime-Date.now())/1000));document.getElementById("timerDisplay").innerText=`${String(Math.floor(left/60)).padStart(2,"0")}:${String(left%60).padStart(2,"0")}`;if(left<=0)clearInterval(timer)}function stopTimer(){clearInterval(timer);document.getElementById("timerDisplay").innerText="00:00"}
function collectWorkout(){let exercises=[...document.querySelectorAll(".exercise-card")].map((card,ei)=>({name:card.dataset.name,type:card.dataset.type,rpe:val(`e${ei}rpe`),note:val(`e${ei}note`),sets:[...card.querySelectorAll("tbody tr")].map((r,si)=>({label:r.children[0].innerText,weight:val(`e${ei}s${si}w`),reps:val(`e${ei}s${si}r`),done:document.getElementById(`e${ei}s${si}d`).checked}))}));return{profileId:prof().id,date:val("workoutDate")||today(),week:val("weekSelect"),workout:val("workoutSelect"),exercises,notes:val("workoutNotes")}}
function workoutKey(w){return `${w.profileId}_${w.date}_${w.week}_${w.workout}`}
function upsertWorkout(w,status){
  let d=data(),key=workoutKey(w);
  w.status=status;
  w.completed=status==="completed";
  w.savedAt=new Date().toISOString();
  let idx=d.workouts.findIndex(x=>workoutKey(x)===key);
  if(idx>=0)d.workouts[idx]=w;else d.workouts.push(w);
  save(d);return w;
}
function saveWorkout(){
  upsertWorkout(collectWorkout(),"draft");
  renderMission();renderProgress();
  alert("Workout saved. You can continue later.");
}
function finishWorkout(){
  upsertWorkout(collectWorkout(),"completed");
  renderMission();renderProgress();
  alert("Workout finished. Weights remain exactly as entered.");
  showTab("mission");
}
function saveDaily(){let carbs=num("carbs"),fiber=num("fiber"),net=Math.max(0,carbs-fiber),sleep=sleepDecimal({sleepHours:val("sleepHours"),sleepMinutes:val("sleepMinutes")}),d=data();d.daily.push({profileId:prof().id,date:val("dailyDate")||today(),weight:val("weight"),waist:val("waist"),calories:val("calories"),protein:val("protein"),carbs:val("carbs"),fiber:val("fiber"),netCarbs:net,fat:val("fat"),steps:val("steps"),water:val("water"),sleepHours:val("sleepHours"),sleepMinutes:val("sleepMinutes"),sleep:sleep.toFixed(2),notes:val("dailyNotes")});save(d);renderMission();renderProgress();alert("Daily saved.")}
function avg(arr,key){let v=arr.map(x=>parseFloat(x[key])).filter(x=>!isNaN(x));return v.length?(v.reduce((a,b)=>a+b,0)/v.length).toFixed(1):"—"}function renderProgress(){let d=data(),p=prof(),daily=d.daily.filter(x=>x.profileId===p.id),last=daily[daily.length-1]||{},last7=daily.slice(-7),wt=(p.startWeight&&last.weight)?(p.startWeight-parseFloat(last.weight)).toFixed(1):"—",wa=(p.startWaist&&last.waist)?(p.startWaist-parseFloat(last.waist)).toFixed(1):"—";document.getElementById("progressCards").innerHTML=`<div class="stat">Weight Lost<div class="big">${wt}</div></div><div class="stat">Waist Lost<div class="big">${wa}”</div></div><div class="stat">7-Day Steps<div class="big">${avg(last7,"steps")}</div></div><div class="stat">7-Day Sleep<div class="big">${avg(last7,"sleep")}h</div></div><div class="stat">7-Day Protein<div class="big">${avg(last7,"protein")}g</div></div><div class="stat">7-Day Net Carbs<div class="big">${avg(last7,"netCarbs")}g</div></div>`;renderHistory()}
function renderHistory(){let el=document.getElementById("historyExercise"),ex=el?.value;if(!ex)return;let hist=data().workouts.filter(w=>w.profileId===prof().id).flatMap(w=>w.exercises.map(e=>({...e,date:w.date,workout:w.workout}))).filter(e=>e.name===ex);document.getElementById("history").innerHTML=hist.length?hist.map(h=>`<div class="stat"><b>${h.date}</b> ${h.workout}<br>${h.sets.map(s=>`${s.label}: ${s.weight}x${s.reps}${s.done?" ✓":""}`).join("<br>")}${h.rpe?`<br>RPE: ${h.rpe}`:""}${h.note?`<br>Note: ${h.note}`:""}</div>`).join(""):"No history yet."}
function addProfile(){let d=data(),name=val("newName").trim();if(!name)return alert("Name required.");let opt=id=>{let n=parseFloat(val(id));return isNaN(n)?null:n};d.profiles.push({id:name.toLowerCase().replace(/[^a-z0-9]+/g,"-")+"-"+Date.now().toString().slice(-4),name,startWeight:opt("newStartWeight"),startWaist:opt("newStartWaist"),goalWaist:opt("newGoalWaist")});save(d);renderProfiles()}
function exportJSON(){download(JSON.stringify(data(),null,2),"mission_ready_v2_7_backup.json","application/json")}function exportCSV(){let d=data(),names=Object.fromEntries(d.profiles.map(p=>[p.id,p.name])),csv="type,profile,date,week,workout,exercise,set,weight,reps,done,waist,bodyweight,calories,protein,carbs,fiber,netCarbs,fat,steps,water,sleepHours,sleepMinutes,sleepDecimal,notes\n";d.daily.forEach(x=>csv+=`daily,"${names[x.profileId]}",${x.date},,,,,,,,,${x.waist},${x.weight},${x.calories},${x.protein},${x.carbs},${x.fiber},${x.netCarbs},${x.fat},${x.steps},${x.water},${x.sleepHours},${x.sleepMinutes},${x.sleep},"${(x.notes||"").replaceAll('"','""')}"\n`);d.workouts.forEach(w=>w.exercises.forEach(e=>e.sets.forEach(s=>csv+=`workout,"${names[w.profileId]}",${w.date},${w.week},"${w.workout}","${e.name}","${s.label}",${s.weight},${s.reps},${s.done},,,,,,,,,,,,,, "${(w.notes||"").replaceAll('"','""')}"\n`)));download(csv,"mission_ready_v2_7_export.csv","text/csv")}
function download(text,file,type){let blob=new Blob([text],{type}),url=URL.createObjectURL(blob),a=document.createElement("a");a.href=url;a.download=file;a.click()}function importJSON(ev){let f=ev.target.files[0];if(!f)return;let r=new FileReader();r.onload=()=>{localStorage.setItem("missionReadyV27",r.result);init();alert("Imported.")};r.readAsText(f)}function clearData(){if(confirm("Delete all local Mission Ready v2.7 data?")){localStorage.removeItem("missionReadyV27");init()}}init();